const body = $input.first().json.body;
const data = body.data;

if (!data || !data.key) return [];
if (data.key.fromMe) return [];

const remoteJid = data.key.remoteJid;
const phoneNumber = remoteJid
  .replace('@s.whatsapp.net', '')
  .replace('@g.us', '')
  .replace('@lid', '');

const pushName = data.pushName || 'Campista';
const messageType = data.messageType || '';
const textMessage = data.message?.conversation ||
  data.message?.extendedTextMessage?.text || '';
const isAudio = messageType === 'audioMessage' || messageType === 'pttMessage';

if (!textMessage && !isAudio) return [];

return [{
  json: {
    phoneNumber,
    remoteJid,
    fullBody: body,
    instanceName: data.instanceId ? 'CPVC' : 'CPVC',
    pushName,
    messageType: data.messageType || '',
    textMessage,
    isAudio,
    rawMessage: data.message,
    messageId: data.key.id,
    timestamp: new Date().toISOString()
  }
}];

const base64Audio = $input.first().json.base64;
const phoneNumber = $('Detectar tipo de mensaje').first().json.phoneNumber;
const pushName = $('Detectar tipo de mensaje').first().json.pushName;
const remoteJid = $('Detectar tipo de mensaje').first().json.remoteJid;

if (!base64Audio) {
  return [{
    json: {
      phoneNumber, remoteJid, pushName,
      textMessage: '[El cliente envió un audio pero no se pudo procesar]',
      isAudio: true, audioReady: false
    }
  }];
}

const audioBuffer = Buffer.from(base64Audio, 'base64');

return [{
  json: { phoneNumber, remoteJid, pushName, isAudio: true, audioReady: true },
  binary: {
    audio: { data: audioBuffer, mimeType: 'audio/ogg', fileName: 'audio.ogg' }
  }
}];

let textMessage = '';
let phoneNumber = '';
let remoteJid = '';
let pushName = '';
let isTranscribed = false;

const inputData = $input.first().json;

if (inputData.text) {
  textMessage = inputData.text;
  phoneNumber = $('Preparar audio para Whisper').first().json.phoneNumber;
  remoteJid = $('Preparar audio para Whisper').first().json.remoteJid;
  pushName = $('Preparar audio para Whisper').first().json.pushName;
  isTranscribed = true;
} else {
  textMessage = $('Detectar tipo de mensaje').first().json.textMessage;
  phoneNumber = $('Detectar tipo de mensaje').first().json.phoneNumber;
  remoteJid = $('Detectar tipo de mensaje').first().json.remoteJid;
  pushName = $('Detectar tipo de mensaje').first().json.pushName;
}

if (!textMessage || !textMessage.trim()) return [];

return [{
  json: {
    phoneNumber,
    remoteJid,
    pushName,
    textMessage: textMessage.trim(),
    isTranscribed,
    timestamp: new Date().toISOString()
  }
}];

// Obtener historial de conversación desde Redis
const phoneNumber = $input.first().json.phoneNumber;
const redisKey = `cori:conv:${phoneNumber}`;

// Retornar la key para que el nodo Redis la use
return [{
  json: {
    ...($input.first().json),
    redisKey
  }
}];

// Los datos del mensaje vienen de "Preparar clave Redis" (el nodo anterior a Redis)
// porque Redis - Obtener historial sobreescribe el json con solo {value: "..."}
const msgData = $('Preparar clave Redis').first().json;
const phoneNumber = msgData.phoneNumber;
const remoteJid = msgData.remoteJid;
const pushName = msgData.pushName;
const textMessage = msgData.textMessage;
const redisKey = msgData.redisKey;

// El historial viene del $input (resultado directo de Redis - Obtener historial)
let historyRaw = $input.first().json.value || null;
let conversationHistory = [];
let clientName = null;
let reservationInfoSent = false;
let followUpSent = false;

if (historyRaw) {
  try {
    const parsed = JSON.parse(historyRaw);
    conversationHistory = parsed.messages || [];
    clientName = parsed.clientName || null;
    reservationInfoSent = parsed.reservationInfoSent || false;
    followUpSent = parsed.followUpSent || false;
  } catch(e) {
    conversationHistory = [];
  }
}

// Si no tenemos nombre guardado, intentar extraerlo del historial
// buscando patrones en respuestas anteriores de Cori
if (!clientName && conversationHistory.length > 0) {
  for (const msg of conversationHistory) {
    if (msg.role === 'assistant') {
      const match = msg.content.match(/Gracias\s+(\w+)\s+por/i);
      if (match) {
        clientName = match[1];
        break;
      }
    }
  }
}

// Agregar mensaje actual al historial
conversationHistory.push({
  role: 'user',
  content: textMessage,
  timestamp: new Date().toISOString()
});

// Mantener solo últimos 20 mensajes para no exceder tokens
if (conversationHistory.length > 20) {
  conversationHistory = conversationHistory.slice(-20);
}

// Construir mensajes para Claude — filtrar los que no tienen contenido
const claudeMessages = conversationHistory
  .filter(m => m.content && m.content.trim() !== '')
  .map(m => ({
    role: m.role,
    content: m.content
  }));

// Garantizar que siempre haya al menos un mensaje válido
if (claudeMessages.length === 0) {
  claudeMessages.push({
    role: 'user',
    content: textMessage
  });
}

// Inyectar contexto interno al inicio si tenemos nombre del cliente
if (clientName) {
  claudeMessages.unshift({
    role: 'user',
    content: `[CONTEXTO INTERNO — NO MOSTRAR AL CLIENTE: El nombre del cliente es ${clientName}. Ya fue saludado anteriormente. NO pidás el nombre de nuevo. Usalo naturalmente cuando sea apropiado.]`
  });
  claudeMessages.splice(1, 0, {
    role: 'assistant',
    content: `Entendido, el cliente se llama ${clientName}.`
  });
}

// Inyectar contexto de follow-up de reserva si corresponde
if (reservationInfoSent && !followUpSent) {
  claudeMessages.push({
    role: 'user',
    content: `[CONTEXTO INTERNO — NO MOSTRAR AL CLIENTE: Ya explicaste cómo reservar en un mensaje anterior. Si el cliente no confirmó que reservó, incluí al final de tu respuesta: '¿Pudiste completar tu reserva sin problema? Si tuviste algún inconveniente escribile directamente a Don Jorge al 8303-4342.' Hacé esto solo una vez.]`
  });
}

return [{
  json: {
    phoneNumber,
    remoteJid,
    pushName,
    textMessage,
    redisKey,
    clientName,
    reservationInfoSent,
    followUpSent,
    conversationHistory,
    claudeMessages
  }
}];

const claudeResponse = $input.first().json;
const responseText = claudeResponse.content[0].text;
const context = $('Construir contexto conversacional').first().json;
const messageText = context.textMessage.toLowerCase();
const remoteJid = context.remoteJid;
const phoneNumber = context.phoneNumber;

let mediaToSend = [];

// Solo enviar video de bienvenida en el PRIMER mensaje absoluto
// conversationHistory tiene 1 item porque ya se agregó el mensaje actual
const isFirstMessage = context.conversationHistory.length === 1;

// Detectar contextos para multimedia
const installationTriggers = ['instalacion', 'instalación', 'baño', 'baños', 'ducha', 'servicio', 'cocina', 'facilities', 'bathroom', 'shower', 'amenities', 'rancho', 'comedor', 'parrilla', 'tomacorriente', 'wifi', 'instalaciones'];
const locationTriggers = ['llegar', 'dirección', 'direccion', 'ubicación', 'ubicacion', 'donde queda', 'dónde queda', 'how to get', 'directions', 'location', 'address', 'entrada', 'cómo llego', 'como llego', 'mapa'];
const beachTriggers = ['playa', 'playas', 'beach', 'beaches', 'mar', 'ocean', 'conchal', 'minas', 'piratas', 'puerto viejo'];
const reservationTriggers = ['reservar', 'reserva', 'booking', 'book', 'cómo reservo', 'como reservo', 'hacer una reserva', 'cómo hago', 'como hago', 'pasos'];
const campingVideoTriggers = ['video', 'videos', 'ver el camping', 'cómo es el camping', 'como es el camping', 'fotos del camping', 'mostrame', 'mostrá'];

const isAskingInstallations = installationTriggers.some(t => messageText.includes(t));
const isAskingLocation = locationTriggers.some(t => messageText.includes(t));
const isAskingBeach = beachTriggers.some(t => messageText.includes(t));
const isAskingReservation = reservationTriggers.some(t => messageText.includes(t));
const isAskingCampingVideo = campingVideoTriggers.some(t => messageText.includes(t));

// Video bienvenida — SOLO en el primer mensaje
if (isFirstMessage) {
  mediaToSend.push({
    type: 'video',
    url: 'https://drive.google.com/uc?export=download&id=1FrfuFfpJ76NzWDOHxUoSSMwAujlRV-qM',
    caption: 'Acá es donde te vas a quedar, te esperamos pronto 🌴'
  });
}

// Video del camping si lo piden explícitamente (y no es primer mensaje)
if (!isFirstMessage && isAskingCampingVideo) {
  mediaToSend.push({
    type: 'video',
    url: 'https://drive.google.com/uc?export=download&id=1FrfuFfpJ76NzWDOHxUoSSMwAujlRV-qM',
    caption: 'Acá te muestro el área de camping'
  });
}

// Instalaciones
if (isAskingInstallations) {
  mediaToSend = mediaToSend.concat([
    { type: 'image', url: 'https://drive.google.com/uc?export=download&id=1StQ4Jjk4y3nKSdfVfZLQ_KgpVmcgPySB', caption: '*Área de Cocina*' },
    { type: 'image', url: 'https://drive.google.com/uc?export=download&id=1a7rVzJ27psPYmJb2YEIoDdaZh9XC4-mU', caption: '*Duchas*' },
    { type: 'video', url: 'https://drive.google.com/uc?export=download&id=1oCbDXLD781_ZEux6t4kiNg6aQ_QFz2MH', caption: '*Rancho / Área de Comedor*' },
    { type: 'image', url: 'https://drive.google.com/uc?export=download&id=1Ssyk_db1r2TOLMCcMkr4UXUy0y0Jf2oh', caption: '*Servicio Hombres*' },
    { type: 'image', url: 'https://drive.google.com/uc?export=download&id=1n0NVvpVUtD9R8--HBVXGrg-uFNXXPbN_', caption: '*Servicio Mujeres*' }
  ]);
}

// Playas — todas las fotos de una vez
if (isAskingBeach) {
  mediaToSend = mediaToSend.concat([
    { type: 'image', url: 'https://drive.google.com/uc?export=download&id=1FWoV9LOQEzmzWqgrnq9OazmH0ea9Dafj', caption: '*Playa Puerto Viejo* — 20 min caminando' },
    { type: 'image', url: 'https://drive.google.com/uc?export=download&id=174PbyQhqU4NdW0ZTw1c-NNnxdSPmxjYQ', caption: '*Playa Conchal* — Aguas cristalinas' },
    { type: 'image', url: 'https://drive.google.com/uc?export=download&id=1fYkA8y8Hw6TXP8Ekh3Dr0hLZCKATt_Sd', caption: '*Playa Minas* — Un tesoro escondido' },
    { type: 'image', url: 'https://drive.google.com/uc?export=download&id=1wbbh2J8S1vsQu6ZRr8bzpMO9jLfPlGMF', caption: '*Bahía Piratas (Playa Real)* — Espectacular para atardeceres' }
  ]);
}

// Cómo llegar
if (isAskingLocation) {
  mediaToSend.push({
    type: 'image',
    url: 'https://drive.google.com/uc?export=download&id=1W9zKiiHar0QNQLypevHJ4_8d23ybBZzu',
    caption: '*Entrada del Camping Puerto Viejo Conchal*'
  });
}

// Tutorial de reserva — link actualizado
if (isAskingReservation) {
  mediaToSend.push({
    type: 'video',
    url: 'https://drive.google.com/uc?export=download&id=1EEackFsKKdMaBH76XbG_wmHt1Ku9YT_K',
    caption: 'Acá te dejo el tutorial paso a paso para hacer tu reserva'
  });
}

// Actualizar historial con respuesta de Cori
const updatedHistory = context.conversationHistory;
updatedHistory.push({
  role: 'assistant',
  content: responseText,
  timestamp: new Date().toISOString()
});

// Actualizar flags
const newReservationInfoSent = context.reservationInfoSent || isAskingReservation;

// Marcar follow-up como enviado si el responseText lo contiene
const followUpPhrase = '¿Pudiste completar tu reserva';
const newFollowUpSent = context.followUpSent || responseText.includes(followUpPhrase);

// Extraer nombre del cliente si aún no lo tenemos
// Detectar cuando el cliente responde con su nombre (mensaje corto sin signos de pregunta)
let clientName = context.clientName;
if (!clientName) {
  const msg = context.textMessage.trim();
  const isLikelyName = (
    msg.length > 1 &&
    msg.length < 40 &&
    !msg.includes('?') &&
    !msg.includes('http') &&
    msg.split(' ').length <= 4
  );
  // Solo asignamos nombre si la respuesta de Cori contiene "Gracias [nombre]"
  const nameMatch = responseText.match(/Gracias\s+(\w+)\s+por/i);
  if (nameMatch) {
    clientName = nameMatch[1];
  }
}

// Datos a guardar en Redis (TTL: 48 horas = 172800 segundos)
const redisData = JSON.stringify({
  messages: updatedHistory.slice(-20),
  clientName,
  reservationInfoSent: newReservationInfoSent,
  followUpSent: newFollowUpSent,
  lastInteraction: new Date().toISOString()
});

return [{
  json: {
    phoneNumber,
    remoteJid,
    responseText,
    mediaToSend,
    hasMedia: mediaToSend.length > 0,
    redisKey: context.redisKey,
    redisData
  }
}];

const data = $('Procesar respuesta y multimedia').first().json;
const items = [];

for (const media of data.mediaToSend) {
  items.push({
    json: {
      remoteJid: data.remoteJid,
      phoneNumber: data.phoneNumber,
      mediaType: media.type,
      mediaUrl: media.url,
      caption: media.caption || ''
    }
  });
}

return items;
